import React, { createContext, useContext, useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';

const ExpenseContext = createContext();

const CATEGORIES = [
  { name: 'Food', icon: '🍔', color: '#f97316' },
  { name: 'Transport', icon: '🚗', color: '#3b82f6' },
  { name: 'Housing', icon: '🏠', color: '#8b5cf6' },
  { name: 'Entertainment', icon: '🎮', color: '#ec4899' },
  { name: 'Healthcare', icon: '💊', color: '#10b981' },
  { name: 'Shopping', icon: '🛍️', color: '#f59e0b' },
  { name: 'Education', icon: '📚', color: '#06b6d4' },
  { name: 'Utilities', icon: '💡', color: '#84cc16' },
  { name: 'Savings', icon: '💰', color: '#14b8a6' },
  { name: 'Other', icon: '📦', color: '#6b7280' },
];

const DEMO_EXPENSES = [
  { id: uuidv4(), title: 'Grocery Shopping', amount: 12500, category: 'FOOD', date: '2026-05-15', note: 'Weekly groceries' },
  { id: uuidv4(), title: 'Uber Ride', amount: 2800, category: 'Transport', date: '2026-05-14', note: '' },
  { id: uuidv4(), title: 'Netflix Subscription', amount: 4500, category: 'Entertainment', date: '2026-05-13', note: 'Monthly sub' },
  { id: uuidv4(), title: 'Electricity Bill', amount: 8000, category: 'Utilities', date: '2026-05-10', note: 'May bill' },
  { id: uuidv4(), title: 'Restaurant Dinner', amount: 7200, category: 'FOOD', date: '2026-05-09', note: 'Family dinner' },
  { id: uuidv4(), title: 'Pharmacy', amount: 3500, category: 'Healthcare', date: '2026-05-08', note: '' },
  { id: uuidv4(), title: 'Bus Fare', amount: 1200, category: 'Transport', date: '2026-05-07', note: '' },
  { id: uuidv4(), title: 'Shoes', amount: 18000, category: 'Shopping', date: '2026-05-05', note: 'New sneakers' },
  { id: uuidv4(), title: 'Online Course', amount: 15000, category: 'Education', date: '2026-05-03', note: 'React course' },
  { id: uuidv4(), title: 'Savings Deposit', amount: 20000, category: 'Savings', date: '2026-05-01', note: 'Emergency fund' },
  { id: uuidv4(), title: 'Rent', amount: 85000, category: 'Housing', date: '2026-05-01', note: 'May rent' },
  { id: uuidv4(), title: 'Jollof Rice', amount: 1800, category: 'FOOD', date: '2026-04-28', note: '' },
  { id: uuidv4(), title: 'Data Subscription', amount: 3000, category: 'Utilities', date: '2026-04-25', note: '10GB data' },
  { id: uuidv4(), title: 'Cinema Ticket', amount: 5500, category: 'Entertainment', date: '2026-04-20', note: '' },
  { id: uuidv4(), title: 'Uber Eats', amount: 4200, category: 'Food & Dining', date: '2026-04-18', note: '' },
  { id: uuidv4(), title: 'Gym Membership', amount: 10000, category: 'Healthcare', date: '2026-04-15', note: '' },
  { id: uuidv4(), title: 'Fuel', amount: 6500, category: 'Transport', date: '2026-04-12', note: '' },
  { id: uuidv4(), title: 'Amazon Shopping', amount: 22000, category: 'Shopping', date: '2026-04-10', note: '' },
  { id: uuidv4(), title: 'Water Bill', amount: 2500, category: 'Utilities', date: '2026-04-05', note: '' },
  { id: uuidv4(), title: 'Savings Deposit', amount: 25000, category: 'Savings', date: '2026-04-01', note: '' },
];

const DEMO_BUDGET = 150000;
const DEMO_INCOME = 250000;

export function ExpenseProvider({ children }) {
  const [expenses, setExpenses] = useState(() => {
    const saved = localStorage.getItem('et_expenses');
    return saved ? JSON.parse(saved) : DEMO_EXPENSES;
  });

  const [budget, setBudget] = useState(() => {
    const saved = localStorage.getItem('et_budget');
    return saved ? Number(saved) : DEMO_BUDGET;
  });

  const [income, setIncome] = useState(() => {
    const saved = localStorage.getItem('et_income');
    return saved ? Number(saved) : DEMO_INCOME;
  });

  const [user, setUser] = useState(() => {
    const saved = localStorage.getItem('et_user');
    return saved ? JSON.parse(saved) : null;
  });

  useEffect(() => {
    localStorage.setItem('et_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('et_budget', String(budget));
  }, [budget]);

  useEffect(() => {
    localStorage.setItem('et_income', String(income));
  }, [income]);

  useEffect(() => {
    if (user) localStorage.setItem('et_user', JSON.stringify(user));
    else localStorage.removeItem('et_user');
  }, [user]);

  const addExpense = (expense) => {
    setExpenses(prev => [{ ...expense, id: uuidv4() }, ...prev]);
  };

  const deleteExpense = (id) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const editExpense = (id, updated) => {
    setExpenses(prev => prev.map(e => e.id === id ? { ...e, ...updated } : e));
  };

  const login = (userData) => setUser(userData);
  const logout = () => setUser(null);

  const totalExpenses = expenses.reduce((sum, e) => sum + e.amount, 0);
  const balance = income - totalExpenses;

  return (
    <ExpenseContext.Provider value={{
      expenses, addExpense, deleteExpense, editExpense,
      budget, setBudget, income, setIncome,
      user, login, logout,
      totalExpenses, balance, categories: CATEGORIES
    }}>
      {children}
    </ExpenseContext.Provider>
  );
}

export const useExpenses = () => useContext(ExpenseContext);
export { CATEGORIES };
